06391742-6a41-4599-87ad-46704751dbdd	fd57270f-d993-45b3-bda9-10945700ecfa	2398470.wav	bdd10e33f396d3f9831977b548da98a57c3405dbc6066875be496962b7d98d57	1881708	gs://quam-voiceqa-dev/raw/fd57270f-d993-45b3-bda9-10945700ecfa/06391742-6a41-4599-87ad-46704751dbdd/2398470.wav	gs://quam-voiceqa-dev/normalized/06391742-6a41-4599-87ad-46704751dbdd/broker.flac	gs://quam-voiceqa-dev/normalized/06391742-6a41-4599-87ad-46704751dbdd/customer.flac	\N	58.80	8000	2	pcm_s16le	2025-11-18 02:06:38+00	9290	27656368	IN	yue-Hant-HK	completed	\N	\N	0	[{"uri": "gs://quam-voiceqa-dev/normalized/06391742-6a41-4599-87ad-46704751dbdd/broker.flac", "segments": [{"start_ms": 524, "end_ms": 844, "text": "喂。", "words": [[524, "喂"]]}, {"start_ms": 844, "end_ms": 844, "text": "系。", "words": [[844, "系"]]}, {"start_ms": 2364, "end_ms": 6924, "text": "誒呢個系我哋誒公司嗰個，即系。", "words": [[2364, "誒"], [2444, "呢"], [2444, "個"], [2444, "系"], [2764, "我"], [2764, "哋"], [2764, "誒"], [4444, "公"], [4524, "司"], [6124, "嗰"], [6764, "個"], [6924, "即"], [6924, "系"]]}, {"start_ms": 10604, "end_ms": 17004, "text": "誒，要電腦先得嘅喎電腦，你電腦噶嘛系嘛。", "words": [[10604, "誒"], [10604, "要"], [12204, "電"], [12604, "腦"], [12764, "先"], [12924, "得"], [13004, "嘅"], [15004, "喎"], [15164, "電"], [15164, "腦"], [15708, "你"], [15996, "電"], [16284, "腦"], [16444, "噶"], [16524, "嘛"], [16764, "系"], [16844, "嘛"]]}, {"start_ms": 21132, "end_ms": 23372, "text": "我我哋都我冇啊我哋。", "words": [[21132, "我"], [21532, "我"], [21692, "哋"], [21772, "都"], [22412, "我"], [22492, "冇"], [22972, "啊"], [22972, "我"], [22972, "哋"]]}, {"start_ms": 23372, "end_ms": 26332, "text": "客户列表啊我。", "words": [[23372, "客"], [23372, "户"], [24412, "列"], [24652, "表"], [24652, "啊"], [26092, "我"]]}, {"start_ms": 31052, "end_ms": 39692, "text": "好好似好似冇噶喎，系啊，唔似以前S P。", "words": [[31052, "好"], [31132, "好"], [32012, "似"], [33372, "好"], [33452, "似"], [33692, "冇"], [33932, "噶"], [34252, "喎"], [34332, "系"], [34732, "啊"], [38252, "唔"], [38252, "似"], [38492, "以"], [38732, "前"], [38972, "S"], [39132, "P"]]}, {"