]]}, {"start_ms": 30620, "end_ms": 36060, "text": "但系我又拉唔到落嚟，拉咗啲之後就後邊嗰個冇得check啊？", "words": [[30620, "但"], [30700, "系"], [30860, "我"], [30940, "又"], [30940, "拉"], [31260, "唔"], [31420, "到"], [31580, "落"], [31740, "嚟"], [31980, "拉"], [32220, "咗"], [32220, "啲"], [32620, "之"], [32780, "後"], [33020, "就"], [33260, "後"], [33500, "邊"], [33580, "嗰"], [33900, "個"], [35500, "冇"], [35500, "得"], [35660, "check"], [35900, "啊"]]}, {"start_ms": 36140, "end_ms": 38940, "text": "死咯，咁樣點搞？", "words": [[36140, "死"], [38060, "咯"], [38220, "咁"], [38300, "樣"], [38300, "點"], [38780, "搞"]]}, {"start_ms": 42668, "end_ms": 54348, "text": "五金啊，系啊，我再問一問嗰個，誒，問一問嗰個邊個，誒，Elephant，好啊好啊，唔該，拜。", "words": [[42668, "五"], [42988, "金"], [42988, "啊"], [44908, "系"], [44988, "啊"], [45628, "我"], [45708, "再"], [45948, "問"], [46188, "一"], [46188, "問"], [46508, "嗰"], [46748, "個"], [46828, "誒"], [49388, "問"], [49580, "一"], [49644, "問"], [49708, "嗰"], [49868, "個"], [50108, "邊"], [50348, "個"], [50588, "誒"], [52188, "Elephant"], [52828, "好"], [52908, "啊"], [53068, "好"], [53228, "啊"], [53468, "唔"], [53548, "該"], [54188, "拜"]]}], "billed": 58.8}]	2026-06-15 01:37:47.339071+00	2026-06-22 08:15:45.789313+00	Maggie	\N	00000000-0000-0000-0000-0000000000d1
