"], [25052, "票"], [25452, "户"], [25452, "口"]]}, {"start_ms": 28524, "end_ms": 30124, "text": "期權户口有三萬幾。", "words": [[28524, "期"], [28684, "權"], [28844, "户"], [29004, "口"], [29244, "有"], [29404, "三"], [29564, "萬"], [29804, "幾"]]}, {"start_ms": 34796, "end_ms": 37036, "text": "股票户口系啦。", "words": [[34796, "股"], [34876, "票"], [35036, "户"], [35116, "口"], [36076, "系"], [36236, "啦"]]}, {"start_ms": 37036, "end_ms": 43196, "text": "誒，仲有咧就係再由股票户口嗰度咧，同我轉七萬蚊到中銀。", "words": [[37036, "誒"], [37996, "仲"], [38156, "有"], [38156, "咧"], [38476, "就"], [38636, "係"], [39036, "再"], [39196, "由"], [39436, "股"], [39676, "票"], [39836, "户"], [40156, "口"], [40316, "嗰"], [40556, "度"], [40556, "咧"], [40876, "同"], [41036, "我"], [41116, "轉"], [41356, "七"], [41676, "萬"], [41996, "蚊"], [42316, "到"], [42636, "中"], [42956, "銀"]]}, {"start_ms": 50908, "end_ms": 55148, "text": "冇錯，咁而家個股票户口應該仲存有二萬二千幾，系咪？", "words": [[50908, "冇"], [50988, "錯"], [50988, "咁"], [50988, "而"], [50988, "家"], [51388, "個"], [51468, "股"], [51548, "票"], [52108, "户"], [52348, "口"], [52828, "應"], [52988, "該"], [53388, "仲"], [53548, "存"], [53868, "有"], [54188, "二"], [54428, "萬"], [54668, "二"], [54828, "千"], [54908, "幾"], [54908, "系"], [54988, "咪"]]}, {"start_ms": 59772, "end_ms": 60412, "text": "哦，OK。", "words": [[59772, "哦"], [60012, "OK"]]}, {"start_ms": 60412, "end_ms": 65132, "text": "OK OK。", "words": [[60412, "OK"], [64252, "OK"]]}, {"start_ms": 72236, "end_ms": 73356, "text": "嗯，yes，correct。", "words": [[72236, "嗯"], [72476, "yes"], [72876, "correct"]]}, {"start_ms": 74316, "end_ms": 78636, "text": "啊，咁啊暫時咁先啦，好唔該曬你，拜拜。", "words": [[74316, "啊"], [74956, "咁"], [74956, "啊"], [74956, "暫"], [75676, "時"], [75756, "咁"], [75916, "先"], [76076, "啦"], [77036, "好"], [77356, "唔"], [77436, "該"], [77756, "曬"], [77996, "你"], [78156, "拜"], [78316, "拜"]]}], "billed": 81.93}]	2026-06-15 01:37:54.380993+00	2026-06-22 08:14:56.458384+00	曾麗圖	二零四四零九	00000000-0000-0000-0000-0000000000d1
