六"], [37068, "千"], [37228, "啊"], [37468, "等"], [37628, "等"], [37868, "系"], [41068, "掛"], [41388, "緊"], [41548, "噶"], [41548, "啦"]]}, {"start_ms": 41548, "end_ms": 41868, "text": "好，嗯，拜拜。", "words": [[41548, "好"], [41548, "嗯"], [41548, "拜"], [41708, "拜"]]}], "billed": 45.4}, {"uri": "gs://quam-voiceqa-dev/normalized/5e5e8ede-c435-405a-b5eb-cdaafd260244/customer.flac", "segments": [{"start_ms": 2476, "end_ms": 3036, "text": "系，早晨。", "words": [[2476, "系"], [2716, "早"], [2956, "晨"]]}, {"start_ms": 3436, "end_ms": 6156, "text": "系，就阿康二零五六零零啊。", "words": [[3436, "系"], [4236, "就"], [5036, "阿"], [5196, "康"], [5436, "二"], [5516, "零"], [5596, "五"], [5676, "六"], [5756, "零"], [5836, "零"], [6076, "啊"]]}, {"start_ms": 9436, "end_ms": 14236, "text": "系，就誒嗰個一三五咩價錢咧想買啫。", "words": [[9436, "系"], [9436, "就"], [9836, "誒"], [9916, "嗰"], [10716, "個"], [10956, "一"], [11116, "三"], [11356, "五"], [11436, "咩"], [11756, "價"], [11916, "錢"], [12236, "咧"], [12236, "想"], [12396, "買"], [14156, "啫"]]}, {"start_ms": 14236, "end_ms": 16396, "text": "系，誒D一四一九一五個模型。", "words": [[14236, "系"], [14636, "誒"], [15116, "D"], [15116, "一"], [15116, "四"], [15116, "一"], [15196, "九"], [15436, "一"], [15516, "五"], [15916, "個"], [16076, "模"], [16236, "型"]]}, {"start_ms": 16396, "end_ms": 20716, "text": "誒，謝輝光，系。", "words": [[16396, "誒"], [16396, "謝"], [20236, "輝"], [20476, "光"], [20716, "系"]]}, {"start_ms": 22988, "end_ms": 22988, "text": "系。", "words": [[22988, "系"]]}, {"start_ms": 22988, "end_ms": 30028, "text": "七點三七，七點三八，誒，七點三七幫我買六千啦。", "words": [[22988, "七"], [25228, "點"], [25788, "三"], [25868, "七"], [26188, "七"], [26508, "點"], [26828, "三"], [26908, "八"], [27548, "誒"], [28108, "七"], [28188, "點"], [28428, "三"], [28748, "七"], [28908, "幫"], [29068, "我"], [29388, "買"], [29388, "六"], [29708, "千"], [29868, "啦"]]}, {"start_ms": 30028, "end_ms": 35628, "text": "誒誒，系，一三五買六千股。", "words": [[30028, "誒"], [30188, "誒"], [30188, "系"], [31788, "一"], [31948, "三"], [32748, "五"], [33868, "買"], [34108, "六"], [34188, "千"], [35388, "股"]]}, {"start_ms": 37964, "end_ms": 42284, "text": "啊，繫系系，七點，啊，啊好，唔該你唔該你，好，拜拜，好嘅。", "words": [[37964, "啊"], [37964, "繫"], [37964, "系"], [37964, "系"], [38124, "七"], [39244, "點"], [39484, "啊"], [40524, "啊"], [40524, "好"], [40524, "唔"], [40604, "該"], [40844, "你"], [41004, "唔"], [41004, "該"], [41004, "你"], [41004, "好"], [41244, "拜"], [41404, "拜"], [41964, "好"], [42124, "嘅"]]}], "billed": 45.4}]	2026-06-15 01:37:53.411286+00	2026-06-22 08:14:58.716232+00	謝輝光	205600	00000000-0000-0000-0000-0000000000d1
