4, "咧"], [5004, "個"], [5084, "人"], [5324, "數"], [5564, "有"], [5644, "冇"], [5804, "增"], [6124, "加"], [6364, "啊"]]}, {"start_ms": 17836, "end_ms": 18956, "text": "都系十三個。", "words": [[17836, "都"], [17996, "系"], [18316, "十"], [18396, "三"], [18636, "個"]]}, {"start_ms": 21116, "end_ms": 21196, "text": "哦。", "words": [[21116, "哦"]]}, {"start_ms": 23884, "end_ms": 25324, "text": "哦，你仲有幾多未復啊？", "words": [[23884, "哦"], [24204, "你"], [24284, "仲"], [24444, "有"], [24604, "幾"], [24764, "多"], [24844, "未"], [25084, "復"], [25324, "啊"]]}, {"start_ms": 29836, "end_ms": 34956, "text": "嗯嗯，哦好啊好啊，得好唔該，好好，拜拜。", "words": [[29836, "嗯"], [30636, "嗯"], [31676, "哦"], [31836, "好"], [32156, "啊"], [32156, "好"], [32716, "啊"], [32716, "得"], [32876, "好"], [34636, "唔"], [34636, "該"], [34636, "好"], [34636, "好"], [34636, "拜"], [34796, "拜"]]}], "billed": 39.0}]	2026-06-15 01:37:49.774957+00	2026-06-22 08:15:32.467732+00	\N	\N	00000000-0000-0000-0000-0000000000d1
