 [36508, "你"], [36668, "落"], [36908, "單"]]}], "billed": 39.96}, {"uri": "gs://quam-voiceqa-dev/normalized/866271a1-a071-4e2e-94c9-1f985995e430/customer.flac", "segments": [{"start_ms": 3436, "end_ms": 8076, "text": "你好，張文傑，户口零一八八一零二四五六。", "words": [[3436, "你"], [3596, "好"], [4316, "張"], [4556, "文"], [4716, "傑"], [5276, "户"], [5436, "口"], [5676, "零"], [5916, "一"], [5996, "八"], [6236, "八"], [6876, "一"], [6956, "零"], [7356, "二"], [7436, "四"], [7676, "五"], [7836, "六"]]}, {"start_ms": 11628, "end_ms": 17228, "text": "中國銀行，三九八八，買十萬股，限價三蚊五毫半。", "words": [[11628, "中"], [11868, "國"], [12028, "銀"], [12268, "行"], [13068, "三"], [13388, "九"], [13548, "八"], [13868, "八"], [14028, "買"], [14348, "十"], [14828, "萬"], [15068, "股"], [15708, "限"], [15948, "價"], [16188, "三"], [16428, "蚊"], [16748, "五"], [16828, "毫"], [16988, "半"]]}, {"start_ms": 25100, "end_ms": 29180, "text": "啱，張單可能要分批成交，都 O K 嘅。", "words": [[25100, "啱"], [25740, "張"], [25980, "單"], [26220, "可"], [26460, "能"], [26700, "要"], [26780, "分"], [27020, "批"], [27260, "成"], [27500, "交"], [28220, "都"], [28460, "O"], [28620, "K"], [28780, "嘅"]]}, {"start_ms": 37820, "end_ms": 38940, "text": "好唔該曬。", "words": [[37820, "好"], [38220, "唔"], [38540, "該"], [38540, "曬"]]}], "billed": 39.96}]	2026-06-12 10:53:25.790287+00	2026-06-22 08:14:47.175176+00	張文傑	0188102456	00000000-0000-0000-0000-0000000000d1
