38636, "兩"], [38796, "萬"], [39036, "股"], [39676, "市"], [39916, "價"], [40076, "盤"]]}, {"start_ms": 40716, "end_ms": 41996, "text": "兩單都確認。", "words": [[40716, "兩"], [41356, "單"], [41356, "都"], [41356, "確"], [41596, "認"]]}, {"start_ms": 44588, "end_ms": 49068, "text": "好，兩單都幫你落咗，多謝李生，拜拜。", "words": [[44588, "好"], [45228, "兩"], [45468, "單"], [45868, "都"], [45868, "幫"], [46108, "你"], [46348, "落"], [46508, "咗"], [47148, "多"], [47308, "謝"], [47468, "李"], [47708, "生"], [48428, "拜"], [48668, "拜"]]}], "billed": 49.62}, {"uri": "gs://quam-voiceqa-dev/normalized/bba771f1-d260-4802-aec3-010356ce31bb/customer.flac", "segments": [{"start_ms": 3308, "end_ms": 7788, "text": "Alex，李家豪啊，account零一八八一零一八八八。", "words": [[3308, "Alex"], [4108, "李"], [4268, "家"], [4508, "豪"], [4748, "啊"], [5308, "account"], [5708, "零"], [5948, "一"], [6188, "八"], [6348, "八"], [6508, "一"], [6668, "零"], [6908, "一"], [7148, "八"], [7308, "八"], [7548, "八"]]}, {"start_ms": 10892, "end_ms": 18252, "text": "想做兩單嘢，第一，匯豐五號仔買五千股，limit一百零二個半。", "words": [[10892, "想"], [11212, "做"], [11372, "兩"], [11612, "單"], [11852, "嘢"], [11852, "第"], [12652, "一"], [13212, "匯"], [13452, "豐"], [14092, "五"], [14252, "號"], [14492, "仔"], [15132, "買"], [15212, "五"], [15612, "千"], [15852, "股"], [16492, "limit"], [16812, "一"], [16972, "百"], [17212, "零"], [17452, "二"], [17852, "個"], [18092, "半"]]}, {"start_ms": 23980, "end_ms": 28460, "text": "仲有小米一八一零，沽兩萬股，市價。", "words": [[23980, "仲"], [24220, "有"], [24380, "小"], [24620, "米"], [25260, "一"], [25500, "八"], [25660, "一"], [25820, "零"], [26540, "沽"], [26700, "兩"], [26860, "萬"], [27180, "股"], [27820, "市"], [28060, "價"]]}, {"start_ms": 42508, "end_ms": 44108, "text": "trên firm đừng coi", "words": [[42508, "trên"], [42668, "firm"], [43468, "đừng"], [44108, "coi"]]}], "billed": 49.62}]	2026-06-12 10:53:25.790287+00	2026-06-22 08:14:50.077088+00	李家豪	0188101888	00000000-0000-0000-0000-0000000000d1
