-b622-9590b8699866/customer.flac", "segments": [{"start_ms": 1964, "end_ms": 2764, "text": "喂，梁小姐啊。", "words": [[1964, "喂"], [2284, "梁"], [2444, "小"], [2524, "姐"], [2764, "啊"]]}, {"start_ms": 5452, "end_ms": 15452, "text": "啊，我二一二，唔系，我二一二九零五咧，嗰個咧七，你睇下先，七五五二啊，嗰個咧我而家誒放咗佢啊。", "words": [[5452, "啊"], [5612, "我"], [5612, "二"], [6012, "一"], [6252, "二"], [6492, "唔"], [7332, "系"], [8172, "我"], [8332, "二"], [8332, "一"], [8492, "二"], [8572, "九"], [8972, "零"], [9052, "五"], [9292, "咧"], [9532, "嗰"], [9692, "個"], [9852, "咧"], [10012, "七"], [10652, "你"], [10812, "睇"], [11052, "下"], [11052, "先"], [11852, "七"], [12092, "五"], [12492, "五"], [13452, "二"], [13692, "啊"], [13692, "嗰"], [13812, "個"], [13932, "咧"], [14012, "我"], [14012, "而"], [14092, "家"], [14492, "誒"], [14892, "放"], [15052, "咗"], [15372, "佢"], [15372, "啊"]]}, {"start_ms": 19644, "end_ms": 26204, "text": "誒，G一七六九零二圖一，四零六啊。", "words": [[19644, "誒"], [19884, "G"], [20044, "一"], [20044, "七"], [20204, "六"], [20204, "九"], [20524, "零"], [20684, "二"], [21564, "圖"], [24204, "一"], [25004, "四"], [25804, "零"], [25964, "六"], [26204, "啊"]]}, {"start_ms": 29004, "end_ms": 32364, "text": "誒，豁曬出去。", "words": [[29004, "誒"], [29164, "豁"], [29404, "曬"], [32284, "出"], [32364, "去"]]}, {"start_ms": 32364, "end_ms": 34124, "text": "系，冇錯。", "words": [[32364, "系"], [33964, "冇"], [34124, "錯"]]}, {"start_ms": 34124, "end_ms": 34444, "text": "好，唔該你。", "words": [[34124, "好"], [34124, "唔"], [34204, "該"], [34444, "你"]]}, {"start_ms": 35404, "end_ms": 35644, "text": "拜拜。", "words": [[35404, "拜"], [35564, "拜"]]}], "billed": 39.55}]	2026-06-15 01:37:50.654448+00	2026-06-22 08:14:46.527106+00	陳允呈	212905	00000000-0000-0000-0000-0000000000d1
