"text": "系。", "words": [[38924, "系"]]}, {"start_ms": 42892, "end_ms": 45772, "text": "嗰個改咗啦，系啊，嗯，拜拜。", "words": [[42892, "嗰"], [43292, "個"], [43292, "改"], [43372, "咗"], [43692, "啦"], [43932, "系"], [44332, "啊"], [44972, "嗯"], [45452, "拜"], [45612, "拜"]]}], "billed": 50.51}, {"uri": "gs://quam-voiceqa-dev/normalized/5402dc79-7762-4e87-a779-a3f67d78fb7f/customer.flac", "segments": [{"start_ms": 1612, "end_ms": 4892, "text": "喂，梁小姐，阿里巴巴，我未入到啊。", "words": [[1612, "喂"], [1692, "梁"], [1932, "小"], [2012, "姐"], [3452, "阿"], [3612, "里"], [3692, "巴"], [3852, "巴"], [4172, "我"], [4252, "未"], [4412, "入"], [4572, "到"], [4652, "啊"]]}, {"start_ms": 5132, "end_ms": 9772, "text": "貴價貴價，而家幾多啊？", "words": [[5132, "貴"], [7372, "價"], [7532, "貴"], [8492, "價"], [8492, "而"], [8492, "家"], [9372, "幾"], [9532, "多"], [9612, "啊"]]}, {"start_ms": 9772, "end_ms": 9772, "text": "哎呀。", "words": [[9772, "哎"], [9772, "呀"]]}, {"start_ms": 17676, "end_ms": 23276, "text": "一五四二啊，四三四二，哦，四三啦。", "words": [[17676, "一"], [17836, "五"], [18156, "四"], [18956, "二"], [19036, "啊"], [20876, "四"], [21116, "三"], [21436, "四"], [22476, "二"], [22636, "哦"], [22636, "四"], [22876, "三"], [23116, "啦"]]}, {"start_ms": 25276, "end_ms": 28796, "text": "借咯借咯，貴州嗰個唔要啦，一五三哦，排隊嗰個。", "words": [[25276, "借"], [25436, "咯"], [25436, "借"], [25436, "咯"], [25756, "貴"], [25996, "州"], [26156, "嗰"], [26316, "個"], [26316, "唔"], [26636, "要"], [26716, "啦"], [27116, "一"], [27436, "五"], [27596, "三"], [27756, "哦"], [28156, "排"], [28316, "隊"], [28556, "嗰"], [28716, "個"]]}, {"start_ms": 28796, "end_ms": 32236, "text": "系，三百。", "words": [[28796, "系"], [29996, "三"], [32156, "百"]]}, {"start_ms": 36428, "end_ms": 36828, "text": "幾多啊？", "words": [[36428, "幾"], [36588, "多"], [36668, "啊"]]}, {"start_ms": 38828, "end_ms": 40828, "text": "一五四三啊？", "words": [[38828, "一"], [38828, "五"], [39228, "四"], [39468, "三"], [40668, "啊"]]}, {"start_ms": 40828, "end_ms": 44508, "text": "OK，嗱嗰個嗰個關咗啦，唔要啦嗬？", "words": [[40828, "OK"], [41228, "嗱"], [41388, "嗰"], [41948, "個"], [42