2, "喎"], [35212, "啊"], [35292, "九"], [35532, "萬"], [35852, "幾"], [36092, "啊"], [36332, "等"], [36332, "陣"], [36332, "先"], [36652, "嚇"], [37132, "八"], [37292, "萬"], [37452, "九"], [37612, "港"], [37932, "幣"], [38092, "啦"]]}, {"start_ms": 40748, "end_ms": 44668, "text": "所以得四萬六，因為未交收啊嘛。", "words": [[40748, "所"], [42908, "以"], [42988, "得"], [43068, "四"], [43228, "萬"], [43468, "六"], [43628, "因"], [43708, "為"], [43788, "未"], [43948, "交"], [44108, "收"], [44428, "啊"], [44668, "嘛"]]}, {"start_ms": 45468, "end_ms": 47468, "text": "咁我睇下佢，我睇下禮拜一先出咯。", "words": [[45468, "咁"], [45548, "我"], [45708, "睇"], [45708, "下"], [45948, "佢"], [46588, "我"], [46668, "睇"], [46828, "下"], [46828, "禮"], [47068, "拜"], [47068, "一"], [47148, "先"], [47228, "出"], [47308, "咯"]]}, {"start_ms": 47628, "end_ms": 49148, "text": "系啊，睇下禮拜一先出，我問下佢先。", "words": [[47628, "系"], [47708, "啊"], [47948, "睇"], [48028, "下"], [48108, "禮"], [48188, "拜"], [48348, "一"], [48348, "先"], [48428, "出"], [48588, "我"], [48716, "問"], [48844, "下"], [48908, "佢"], [48988, "先"]]}, {"start_ms": 49708, "end_ms": 50668, "text": "唔該，拜拜。", "words": [[49708, "唔"], [49788, "該"], [50108, "拜"], [50268, "拜"]]}], "billed": 54.4}, {"uri": "gs://quam-voiceqa-dev/normalized/6e713cfc-7677-43dd-9083-cbf3a9f27d7e/customer.flac", "segments": [{"start_ms": 1836, "end_ms": 7676, "text": "桃仔莊唔到七萬喎，佢before掉，佢誒誒星期一先交收啊。", "words": [[1836, "桃"], [1996, "仔"], [2156, "莊"], [2396, "唔"], [2556, "到"], [2556, "七"], [2796, "萬"], [3116, "喎"], [4316, "佢"], [4556, "before"], [4876, "掉"], [5356, "佢"], [6636, "誒"], [6956, "誒"], [6956, "星"], [6956, "期"], [6956, "一"], [6956, "先"], [6956, "交"], [7116, "收"], [7356, "啊"]]}, {"start_ms": 9276, "end_ms": 13196, "text": "佢有，佢估咗只誒五號仔四萬二千蚊。", "words": [[9276, "佢"], [9436, "有"], [9916, "佢"], [10076, "估"], [10236, "咗"], [10316, "只"], [10636, "誒"], [11756, "五"], [11836, "號"], [11996, "仔"], [12396, "四"], [12636, "萬"], [12876, "二"], [12876, "千"], [13116, "蚊"]]}, {"start_ms": 13196, "end_ms": 21996, "text": "誒，今日最多出到二萬六，如果佢夾埋佢琴頭先喺option轉，咁咪四萬六咯。", "words": [[13196, "誒"], [13276, "今"], [13516, "日"], [15996, "最"], [15996, "多"], [16636, "出"], [16716, "到"], [16716, "二"], [17036, "萬"], [17036, "六"], [17276, "如"], [17756, "果"], [17996, "佢"], [18156, "夾"], [18476, "埋"], [18636, "佢"], [19356, "琴"], [19676, "頭"], [19756, "先"], [20076, "喺"], [20396, "option"], [20396, "轉"], [21036, "咁"], [21036, "咪"], [21276, "四"], [21436, "萬"], [21596, "六"], [21676, "咯"]]}, {"start_ms": 23116, "end_ms": 23356, "text": "嗯。", "words": [[23116, "嗯"]]}, {"start_ms": 26316, "end_ms": 27276, "text": "系啊，我做咗噶啦。", "words": [[26316, "系"], [26316, "啊"], [26636, "我"], [26636, "做"], [26796, "咗"], [26956, "噶"], [27116, "啦"]]}, {"start_ms": 27916, "end_ms": 34956, "text": "咁但系因為其實你而家前台睇佢都繫有八萬幾蚊嘅應該。", "words": [[27916, "咁"], [28076, "但"], [28316, "系"], [28396, "因"], [28476, "為"], [28556, "其"], [28636, "實"], [28876, "你"], [28956, "而"], [29036, "家"], [29036, "前"], [29196, "台"], [29596, "睇"], [29676, "佢"], [29676, "都"], [29836, "繫"], [29916, "有"], [30156, "八"], [30316, "萬"], [30556, "幾"], [30876, "蚊"], [31196, "嘅"], [31836, "應"], [34396, "該"]]}, {"start_ms": 34956, "end_ms": 37036, "text": "八萬九咯而家見到，系啊。", "words": [[34956, "八"], [34956, "萬"], [35116, "九"], [35196, "咯"], [35196, "而"], [35356, "家"], [35356, "見"], [35516, "到"], [36476, "系"], [36556, "啊"]]}, {"start_ms": 38636, "end_ms": 43969, "text": "系咯系咯，但系我後台加埋嗰二萬蚊，我哋睇後台為準嘅，就係四萬六。", "words": [[38636, "系"], [38716, "咯"], [38796, "系"], [38796, "咯"], [38796, "但"], [39396, "系"], [39476, "我"], [39596, "後"], [39836, "台"], [39996, "加"], [40316, "埋"], [40476, "嗰"], [40716, "二"], [40716, "萬"], [41036, "蚊"], [41036, "我"], [41356, "哋"], [41436, "睇"], [41676, "後"], [41756, "台"], [42396, "為"], [42716, "準"], [42836, "嘅"], [42956, "就"], [43004, "係"], [43100, "四"], [43196, "萬"], [43662, "六"]]}, {"start_ms": 44276, "end_ms": 48876, "text": "冇錯，一系你就禮拜，禮拜一先租咯，系咯，你問下佢咯。", "words": [[44276, "冇"], [44889, "錯"], [45356, "一"], [46956, "系"], [47116, "你"], [47116, "就"], [47836, "禮"], [47996, "拜"], [47996, "禮"], [479