252, "零"], [38412, "三"], [38652, "你"], [38732, "稍"], [38892, "等"], [38972, "啊"]]}, {"start_ms": 40492, "end_ms": 41452, "text": "你全名是什麼？", "words": [[40492, "你"], [40652, "全"], [40812, "名"], [40972, "是"], [41052, "什"], [41132, "麼"]]}, {"start_ms": 44492, "end_ms": 45932, "text": "嗯，身份證號要對一下。", "words": [[44492, "嗯"], [44732, "身"], [44892, "份"], [44972, "證"], [45132, "號"], [45292, "要"], [45292, "對"], [45452, "一"], [45612, "下"]]}, {"start_ms": 47852, "end_ms": 48092, "text": "嗯。", "words": [[47852, "嗯"]]}, {"start_ms": 50348, "end_ms": 50668, "text": "嗯。", "words": [[50348, "嗯"]]}, {"start_ms": 52748, "end_ms": 55068, "text": "好，你做的是那那那些股票啊？", "words": [[52748, "好"], [53308, "你"], [53628, "做"], [53788, "的"], [53868, "是"], [54028, "那"], [54268, "那"], [54348, "那"], [54508, "些"], [54668, "股"], [54828, "票"], [54988, "啊"]]}, {"start_ms": 55068, "end_ms": 56268, "text": "是C M E的那些嗎？", "words": [[55068, "是"], [55228, "C"], [55468, "M"], [55628, "E"], [55628, "的"], [55788, "那"], [55868, "些"], [56028, "嗎"]]}, {"start_ms": 61068, "end_ms": 65068, "text": "小黃即係就係C M E裏裏裏邊啊，即係個。", "words": [[61068, "小"], [61228, "黃"], [61388, "即"], [61468, "係"], [61548, "就"], [61628, "係"], [61788, "C"], [61868, "M"], [62188, "E"], [62668, "裏"], [62828, "裏"], [62908, "裏"], [63388, "邊"], [63388, "啊"], [64588, "即"], [64668, "係"], [65068, "個"]]}, {"start_ms": 65068, "end_ms": 74108, "text": "對對對，C M E嗰邊即係交易所嗰邊，紐約紐約交易所嗰邊，佢哋系統有問題啊，所以而家交易唔到，全世界都交易唔到。", "words": [[65068, "對"], [65068, "對"], [65068, "對"], [65948, "C"], [66108, "M"], [66268, "E"], [66428, "嗰"], [66668, "邊"], [66828, "即"], [66828, "係"], [67148, "交"], [67228, "易"], [67388, "所"], [67628, "嗰"], [67708, "邊"], [68108, "紐"], [68348, "約"], [68428, "紐"], [68428, "約"], [68588, "交"], [68748, "易"], [68828, "所"], [68988, "嗰"], [69228, "邊"], [69628, "佢"], [69628, "哋"], [70028, "系"], [70348, "統"], [70428, "有"], [70508, "問"], [70828, "題"], [70988, "啊"], [71708, "所"], [71788, "以"], [71868, "而"], [72108, "家"], [72268, "交"], [72268, "易"], [72428, "唔"], [7250