"], [3964, "天"], [4124, "是"], [4524, "那"], [5564, "個"], [5724, "我"], [5804, "上"], [6124, "午"], [6204, "在"], [6364, "做"], [6524, "交"], [6764, "易"], [6924, "怎"], [7084, "麼"], [7564, "現"], [7564, "在"], [7724, "盤"], [7964, "面"], [8124, "那"], [8444, "個"], [8524, "都"], [8524, "報"], [8844, "價"], [8924, "都"], [9084, "停"], [9244, "了"], [9404, "交"], [9644, "易"], [9724, "都"], [9804, "停"], [10044, "了"], [10204, "是"], [10364, "什"], [10364, "麼"], [10604, "原"], [10764, "因"]]}, {"start_ms": 15436, "end_ms": 23116, "text": "我賬號號碼是呃是一一零零幺五七九呃幺零零啊。", "words": [[15436, "我"], [15596, "賬"], [15836, "號"], [16076, "號"], [16076, "碼"], [16236, "是"], [16956, "呃"], [18076, "是"], [18476, "一"], [18556, "一"], [18636, "零"], [19356, "零"], [20796, "幺"], [20956, "五"], [21036, "七"], [21276, "九"], [22156, "呃"], [22316, "幺"], [22636, "零"], [22796, "零"], [22956, "啊"]]}, {"start_ms": 26892, "end_ms": 40412, "text": "那個，幺幺零零，啊，我看一下現在這個，我想問一下現在報價幺零零，幺五八九七零三，啊，幺零零幺五八九七零三。", "words": [[26892, "那"], [27052, "個"], [28652, "幺"], [28972, "幺"], [28972, "零"], [29132, "零"], [29372, "啊"], [32252, "我"], [32332, "看"], [32492, "一"], [32572, "下"], [32652, "現"], [32812, "在"], [32812, "這"], [33372, "個"], [33452, "我"], [33452, "想"], [33612, "問"], [33772, "一"], [33852, "下"], [33932, "現"], [34092, "在"], [34172, "報"], [34332, "價"], [34572, "幺"], [34732, "零"], [34812, "零"], [35692, "幺"], [35852, "五"], [36012, "八"], [36172, "九"], [36412, "七"], [36572, "零"], [36652, "三"], [37612, "啊"], [39212, "幺"], [39292, "零"], [39372, "零"], [39532, "幺"], [39612, "五"], [39804, "八"], [39868, "九"], [39932, "七"], [40012, "零"], [40172, "三"]]}, {"start_ms": 43132, "end_ms": 44252, "text": "我是賈明軍。", "words": [[43132, "我"], [43292, "是"], [43532, "賈"], [43772, "明"], [43932, "軍"]]}, {"start_ms": 47020, "end_ms": 52140, "text": "身份證呃六五四零零幺幺九六三零八二幺四九幺X。", "words": [[47020, "身"], [47180, "份"], [47260, "證"], [47820, "呃"], [48380, "六"], [48700, "五"], [48780, "四"], [48860, "零"], [49020, "零"], [49180, "幺"], [49340, "幺"], [49500, "九"], [49660, "六"], [49900, "三"], [50620, "零"], [50940, "八"], [51180, "二"], [51180, "幺"], [51420, "四"], [51500, "九"], [51660, "幺"], [51900, "X"]]}, {"start_ms": 57100, "end_ms": 60380, "text": "不是，我做的是那個小呃小黃金。", "words": [[57100, "不"], [57180, "是"], [57340, "我"], [57500, "做"], [57660, "的"], [57740, "是"], [57900, "那"], [58780, "個"], [59340, "小"], [59500, "呃"], [59820, "小"], [59980, "黃"], [60380, "金"]]}, {"start_ms": 62636, "end_ms": 64316, "text": "小王，你今天那個盤怎麼都停了？", "words": [[62636, "小"], [62796, "王"], [62876, "你"], [62956, "今"], [63116, "天"], [63196, "那"], [63276, "個"], [63356, "盤"], [63676, "怎"], [63756, "麼"], [63836, "都"], [63916, "停"], [64236, "了"]]}, {"start_ms": 64396, "end_ms": 66476, "text": "報價也沒有報價，不動了咧，到中午啊。", "words": [[64396, "報"], [64556, "價"], [64716, "也"], [64796, "沒"], [64956, "有"], [65036, "報"], [65196, "價"], [65276, "不"], [65436, "動"], [65596, "了"], [65676, "咧"], [65836, "到"], [65996, "中"], [66236, "午"], [66316, "啊"]]}, {"start_ms": 72684, "end_ms": 72764, "text": "啊。", "words": [[72684, "啊"]]}, {"start_ms": 76492, "end_ms": 81612, "text": "哦，系統有問題，怎沒通呃，我我在那個華附平台沒查到，沒有通知啊。", "words": [[76492, "哦"], [76812, "系"], [76972, "統"], [77132, "有"], [77612, "問"], [77772, "題"], [77872, "怎"], [77912, "沒"], [77932, "通"], [78092, "呃"], [78732, "我"], [78892, "我"], [79052, "在"], [79372, "那"], [79692, "個"], [79772, "華"], [79852, "附"], [80012, "平"], [80172, "台"], [80332, "沒"], [80492, "查"], [80652, "到"], [80812, "沒"], [81052, "有"], [81052, "通"], [81212, "知"], [81372, "啊"]]}, {"start_ms": 87500, "end_ms": 88940, "text": "哦，你話跳出嚟有個通知是吧？", "words": [[87500, "哦"], [87580, "你"], [87660, "話"], [87980, "跳"], [87980, "出"], [88060, "嚟"], [88140, "有"], [88220, "個"], [88380, "通"], [88460, "知"], [88540, "是"], [88620, "吧"]]}, {"start_ms": 92332, "end_ms": 96652, "text": "那我現在這個，他停止了，我這個攤位在那，怎麼搞也也搞不成啊。", "words": [[92332, "那"], [92412, "我"], [92572, "現"], [92652, "在"], [92892, "這"], [93612, "個"], [93692, "他"], [93692, "停"], [93932, "止"], [94012, "了"], [94172, "我"], [94332, "這"], [94572, "個"], [94972, "攤"], [94972, "位"], [94972, "在"], [95212, "那"], [95212, "怎"], [95372, "麼"], [95532, "搞"], [95692, "也"], [96012, "也"], [96092, "搞"], [96172, "不"], [96332, "成"], [96412, "啊"]]}, {"start_ms": 102028, "end_ms": 102508, "text": "哦。", "words": [[102028, "哦"]]}, {"start_ms": 106412, "end_ms": 107052, "text": "哦。", "words": [[106412, "哦"]]}, {"start_ms": 107052, "end_ms": 110892, "text": "哦交易所系統它那個是停了停了是不是啊？", "words": [[107052, "哦"], [108652, "交"], [108812, "易"], [108892, "所"], [109052, "系"], [109212, "統"], [109292, "它"], [109452, "那"], [109532, "個"], [109612, "是"], [109772, "停"], [110092, "了"], [110252, "停"], [110412, "了"], [110492, "是"], [110572, "不"], [110652, "是"], [110892, "啊"]]}, {"start_ms": 111692, "end_ms": 112972, "text": "它講什麼原因了沒有？", "words": [[111692, "它"], [111772, "講"], [112012, "什"], [112172, "麼"], [112332, "原"], [112492, "因"], [112652, "了"], [112732, "沒"], [112812, "有"]]}, {"start_ms": 112972, "end_ms": 119932, "text": "哦，那我我登進去沒有跳的通知啊，我就我登登進去沒有跳通知，啊？", "words": [[112972, "哦"], [115372, "那"], [115532, "我"], [115932, "我"], [116012, "登"], [116252, "進"], [116332, "去"], [116412, "沒"], [116652, "有"], [116652, "跳"], [116812, "的"], [116892, "通"], [117052, "知"], [117212, "啊"], [117692, "我"], [117852, "就"], [118012, "我"], [118092, "登"], [118252, "登"], [118332, "進"], [118732, "去"], [118732, "沒"], [118972, "有"], [118972, "跳"], [119132, "通"], [119292, "知"], [119772, "啊"]]}, {"start_ms": 121852, "end_ms": 125532, "text": "好，你們那也停了都停了是不是包括外匯啊？", "words": [[121852, "好"], [123052, "你"], [123212, "們"], [123372, "那"], [123452, "也"], [123612, "停"], [123772, "了"], [123932, "都"], [124092, "停"], [124252, "了"], [124332, "是"], [124412, "不"], [124492, "是"], [124572, "包"], [124812, "括"], [124972, "外"], [125132, "匯"], [125292, "啊"]]}, {"start_ms": 130284, "end_ms": 132124, "text": "你就是你那个合约全停了是吧？", "words": [[130284, "你"], [130524, "就"], [130684, "是"], [130684, "你"], [130844, "那"], [130924, "个"], [131004, "合"], [131164, "约"], [131324, "全"], [131484, "停"], [131644, "了"], [131804, "是"], [131884, "吧"]]}, {"start_ms": 133964, "end_ms": 136924, "text": "哦，我就说问一下，我也没查到通知什么没有。", "words": [[133964, "哦"], [134764, "我"], [134844, "就"], [135004, "说"], [135164, "问"], [135324, "一"], [135404, "下"], [135484, "我"], [135564, "也"], [135644, "没"], [135804, "查"], [135964, "到"], [136124, "通"], [136284, "知"], [136444, "什"], [136524, "么"], [136604, "没"], [136764, "有"]]}, {"start_ms": 137164, "end_ms": 138764, "text": "哦，好，那我知道了啊。", "words": [[137164, "哦"], [137484, "好"], [137884, "那"], [137964, "我"], [138124, "知"], [138204, "道"], [138364, "了"], [138524, "啊"]]}, {"start_ms": 143436, "end_ms": 146156, "text": "那啥時候能通知能能修好是啊。", "words": [[143436, "那"], [143516, "啥"], [143756, "時"], [143836, "候"], [143996, "能"], [144076, "通"], [144396, "知"], [144476, "能"], [144716, "能"], [144956, "修"], [145196, "好"], [145356, "是"], [145916, "啊"]]}, {"start_ms": 149548, "end_ms": 150188, "text": "好好。", "words": [[149548, "好"], [149868, "好"]]}, {"start_ms": 152844, "end_ms": 153564, "text": "好好。", "words": [[152844, "好"], [153244, "好"]]}, {"start_ms": 153564, "end_ms": 160044, "text": "好嘛好好，啊，行，知道了，好，拜拜，哎，哎，拜拜。", "words": [[153564, "好"], [155564, "嘛"], [155724, "好"], [155964, "好"], [156364, "啊"], [156684, "行"], [157084, "知"], [157164, "道"], [157324, "了"], [157884, "好"], [158044, "拜"], [158204, "拜"], [159484, "哎"], [159484, "哎"], [159724, "拜"], [159884, "拜"]]}], "billed": 162.64}]	2026-06-15 01:37:57.449856+00	2026-06-22 08:16:04.720668+00	賈明軍	1001589703	00000000-0000-0000-0000-0000000000d1
