], [31436, "六"], [31436, "十"], [32636, "四"], [33196, "個"], [33196, "一"], [33196, "三"], [33276, "百"]]}, {"start_ms": 36972, "end_ms": 39532, "text": "系，好，嗯，拜拜。", "words": [[36972, "系"], [38332, "好"], [38812, "嗯"], [39052, "拜"], [39212, "拜"]]}], "billed": 43.92}, {"uri": "gs://quam-voiceqa-dev/normalized/939b9cb4-8c56-48c8-9c2c-83adbb82b0d7/customer.flac", "segments": [{"start_ms": 3340, "end_ms": 5420, "text": "梁小姐啊，一零二四知道啊？", "words": [[3340, "梁"], [3500, "小"], [3660, "姐"], [3820, "啊"], [4540, "一"], [4700, "零"], [4780, "二"], [4940, "四"], [4940, "知"], [5100, "道"], [5260, "啊"]]}, {"start_ms": 5420, "end_ms": 5500, "text": "系。", "words": [[5420, "系"]]}, {"start_ms": 12812, "end_ms": 14812, "text": "喂，見到啊。", "words": [[12812, "喂"], [14492, "見"], [14652, "到"], [14732, "啊"]]}, {"start_ms": 17324, "end_ms": 23324, "text": "幫我入三百啊，直，直接入吧，嚇。", "words": [[17324, "幫"], [17804, "我"], [17884, "入"], [18284, "三"], [18444, "百"], [18524, "啊"], [20684, "直"], [20764, "直"], [20764, "接"], [21004, "入"], [21404, "吧"], [23324, "嚇"]]}, {"start_ms": 35148, "end_ms": 39068, "text": "跌咗六十四個日啊，OK，唔該。", "words": [[35148, "跌"], [35228, "咗"], [35468, "六"], [35628, "十"], [35788, "四"], [36348, "個"], [36508, "日"], [36588, "啊"], [37708, "OK"], [38668, "唔"], [38748, "該"]]}], "billed": 43.92}]	2026-06-15 01:37:51.094299+00	2026-06-22 08:14:50.583771+00	華夫	零九零	00000000-0000-0000-0000-0000000000d1
