ds": [[33484, "啊"], [33644, "身"], [33724, "份"], [33884, "證"], [34204, "身"], [34284, "份"], [34444, "證"]]}, {"start_ms": 36444, "end_ms": 37324, "text": "好啊，掛住啊。", "words": [[36444, "好"], [36684, "啊"], [36844, "掛"], [37004, "住"], [37164, "啊"]]}, {"start_ms": 38124, "end_ms": 38764, "text": "嗯，拜拜。", "words": [[38124, "嗯"], [38444, "拜"], [38604, "拜"]]}, {"start_ms": 39244, "end_ms": 39964, "text": "嗯，拜拜。", "words": [[39244, "嗯"], [39484, "拜"], [39644, "拜"]]}], "billed": 44.74}, {"uri": "gs://quam-voiceqa-dev/normalized/1c674f76-57cf-4f5b-903b-b28cb66d0733/customer.flac", "segments": [{"start_ms": 2080, "end_ms": 2720, "text": "喂，梁小姐。", "words": [[2080, "喂"], [2160, "梁"], [2480, "小"], [2640, "姐"]]}, {"start_ms": 4800, "end_ms": 6000, "text": "幫我入阿里巴巴。", "words": [[4800, "幫"], [4960, "我"], [5040, "入"], [5120, "阿"], [5360, "里"], [5520, "巴"], [5680, "巴"]]}, {"start_ms": 6080, "end_ms": 13440, "text": "嘢幾多啊？", "words": [[6080, "嘢"], [6080, "幾"], [13120, "多"], [13200, "啊"]]}, {"start_ms": 13680, "end_ms": 14400, "text": "大箱啲。", "words": [[13680, "大"], [13840, "箱"], [14080, "啲"]]}, {"start_ms": 18124, "end_ms": 25644, "text": "哦，幫我買一百五十三個，劈得，三百。", "words": [[18124, "哦"], [18444, "幫"], [18684, "我"], [18844, "買"], [19004, "一"], [19084, "百"], [19244, "五"], [19564, "十"], [19644, "三"], [20204, "個"], [20524, "劈"], [22124, "得"], [22364, "三"], [25564, "百"]]}, {"start_ms": 29740, "end_ms": 39900, "text": "系，嗱，報個牌啦，六四九二九一，好啦，幫我掛住啦，OK。", "words": [[29740, "系"], [29740, "嗱"], [30700, "報"], [31580, "個"], [32940, "牌"], [33420, "啦"], [35580, "六"], [35660, "四"], [35660, "九"], [35660, "二"], [35660, "九"], [36060, "一"], [36140, "好"], [38060, "啦"], [38380, "幫"], [38540, "我"], [38620, "掛"], [38860, "住"], [38940, "啦"], [39740, "OK"]]}], "billed": 44.74}]	2026-06-15 01:37:49.267701+00	2026-06-22 08:16:01.457358+00	華叔	六四九二九一	00000000-0000-0000-0000-0000000000d1
