er.flac", "segments": [{"start_ms": 4044, "end_ms": 11164, "text": "你好，我是吴永欣，账户0188103999，我想买友邦保险。", "words": [[4044, "你"], [4204, "好"], [5004, "我"], [5004, "是"], [5244, "吴"], [5484, "永"], [5644, "欣"], [6364, "账"], [6444, "户"], [6764, "01881"], [9564, "03999"], [9644, "我"], [9724, "想"], [9964, "买"], [10204, "友"], [10364, "邦"], [10604, "保"], [10844, "险"]]}, {"start_ms": 17036, "end_ms": 19276, "text": "2000股，市价就可以。", "words": [[17036, "2000"], [17916, "股"], [18076, "市"], [18316, "价"], [18556, "就"], [18796, "可"], [19036, "以"]]}, {"start_ms": 26316, "end_ms": 27516, "text": "对的，谢谢。", "words": [[26316, "对"], [26476, "的"], [26956, "谢"], [27196, "谢"]]}], "billed": 33.03}]	2026-06-12 10:53:08.697144+00	2026-06-22 08:15:26.279317+00	吴永欣	0188103999	00000000-0000-0000-0000-0000000000d1
