], [37356, "拜"]]}], "billed": 43.19}, {"uri": "gs://quam-voiceqa-dev/normalized/53ca9061-4338-4b94-b77e-14063a508207/customer.flac", "segments": [{"start_ms": 1772, "end_ms": 3372, "text": "我號碼一零零一五。", "words": [[1772, "我"], [1932, "號"], [2092, "碼"], [2252, "一"], [2572, "零"], [2812, "零"], [2812, "一"], [3132, "五"]]}, {"start_ms": 8428, "end_ms": 9788, "text": "七五七零三。", "words": [[8428, "七"], [8988, "五"], [9148, "七"], [9308, "零"], [9548, "三"]]}, {"start_ms": 14940, "end_ms": 17660, "text": "系，行珠大橋要幾多？", "words": [[14940, "系"], [15500, "行"], [15580, "珠"], [16860, "大"], [17100, "橋"], [17180, "要"], [17260, "幾"], [17420, "多"]]}, {"start_ms": 20108, "end_ms": 20188, "text": "系。", "words": [[20108, "系"]]}, {"start_ms": 23276, "end_ms": 24076, "text": "你講咩啊？", "words": [[23276, "你"], [23676, "講"], [23756, "咩"], [24076, "啊"]]}, {"start_ms": 26508, "end_ms": 28668, "text": "點樣升得咁快啊同我哋加一張啊。", "words": [[26508, "點"], [26668, "樣"], [26908, "升"], [26988, "得"], [27308, "咁"], [27308, "快"], [27468, "啊"], [27628, "同"], [27788, "我"], [27868, "哋"], [28028, "加"], [28268, "一"], [28428, "張"], [28588, "啊"]]}, {"start_ms": 30188, "end_ms": 30348, "text": "系。", "words": [[30188, "系"]]}, {"start_ms": 32460, "end_ms": 37420, "text": "好，唔該你，嗯，拜拜。", "words": [[32460, "好"], [36860, "唔"], [36940, "該"], [37020, "你"], [37040, "嗯"], [37080, "拜"], [37100, "拜"]]}], "billed": 43.19}]	2026-06-15 01:37:46.891695+00	2026-06-22 08:16:06.877726+00	華夫	1001575703	00000000-0000-0000-0000-0000000000d1
